from pathlib import Path
import re


def replace_once(text: str, old: str, new: str, label: str) -> str:
    if old not in text:
        raise SystemExit(f"missing replacement target: {label}")
    return text.replace(old, new, 1)

path = Path("public/js/owner-control-center.js")
text = path.read_text()

# Human labels for holder roles and observed behavior.
text = replace_once(
    text,
    "const STATUS_LABELS={healthy:",
    "const HOLDER_ROLE_LABELS={externally_owned_wallet:'Normal cüzdan',owner_unresolved:'Owner çözülemedi',wallet_account_unavailable:'Wallet metadatası yok',program_controlled_unresolved:'Program rolü çözülemedi',pump_bonding_curve_or_protocol_vault:'Pump bonding curve',pump_liquidity_vault:'Pump likidite kasası',burn_sink:'Burn adresi',executable_program_controlled:'Program hesabı',mixed_control_surface:'Karışık kontrol'};\nconst HOLDER_BEHAVIOR_LABELS={common_exit_recipient_observed:'Ortak çıkış gözlendi',token_outflow_observed:'Token çıkışı gözlendi',acquisition_observed_no_outflow_in_bounded_window:'Alım gözlendi · çıkış yok',wallet_observed_no_target_token_flow:'Wallet görüldü · token akışı yok',holding_observed_no_behavior_window:'Davranış penceresi yok',owner_role_unresolved:'Rol çözülmedi',protocol_or_non_wallet_inventory:'Protokol envanteri'};\nconst STATUS_LABELS={healthy:",
    "holder labels",
)

anchor = "function holderClusterHTML(raw){"
helpers = r'''function usd(v,digits=2){if(v===null||v===undefined||v===''||!Number.isFinite(Number(v)))return'—';const n=Number(v),max=Math.abs(n)<1?Math.max(digits,6):digits;return new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',minimumFractionDigits:0,maximumFractionDigits:max}).format(n)}
function holderRoleLabel(v){return HOLDER_ROLE_LABELS[String(v||'')]||label(v||'unknown')}
function holderBehaviorLabel(v){return HOLDER_BEHAVIOR_LABELS[String(v||'')]||label(v||'unknown')}
function holderDuration(row){if(row.acquisition_observed&&Number.isFinite(Number(row.observed_holding_days)))return`${num(row.observed_holding_days)}g+ gözlenen tutuş`;if(Number(row.observed_activity_age_days)>0)return`${num(row.observed_activity_age_days)}g wallet geçmişi`;return'Bilinmiyor'}
function holderIdentity(row){return row.owner_wallet||arr(row.token_accounts)[0]||'Çözümlenemedi'}
function holderIntelligenceHTML(raw){const h=obj(raw),rows=arr(h.rows),m=obj(h.market);if(!h.available||!rows.length)return'<div class="warning-box section-gap"><b>Holder Intelligence üretilemedi.</b><br>Arz veya en büyük token-account verisi alınamadı.</div>';const top=rows[0]||{};return`<details class="owner-details section-gap" open><summary><span><b>Holder Intelligence · Gerçek sahiplik ve değer</b><small>Owner bazında birleştirilmiş bakiye, yüzde, USD değer, gözlenen tutuş ve davranış.</small></span><span>⌄</span></summary><div class="grid compact-grid section-gap">${kpi('Referans fiyat',m.price_usd?usd(m.price_usd,10):'—',`${esc(m.best_pair_dex||'DEX')} · en likit pair`,'tone-cyan','$')}${kpi('Piyasa değeri',m.market_cap_usd?usd(m.market_cap_usd):'—',`FDV ${m.fdv_usd?usd(m.fdv_usd):'—'}`,'tone-cyan','◇')}${kpi('24s hacim',m.volume_24h_usd?usd(m.volume_24h_usd):'—',`${num(m.buys_24h)} alım · ${num(m.sells_24h)} satış`,'tone-cyan','↕')}${kpi('Likidite',m.liquidity_usd?usd(m.liquidity_usd):'—',`${num(m.pair_count)} Solana pair`,'tone-green','≈')}${kpi('En büyük kontrol',`${num(h.top_owner_percentage)}%`,`${num(h.top_owner_balance)} token`,'tone-red','1')}${kpi('Referans değeri',h.top_owner_reference_usd_value==null?'—':usd(h.top_owner_reference_usd_value),'Likidasyon garantisi değildir','tone-amber','$')}</div>${h.final_verdict_blocked?'<div class="warning-box section-gap"><b>Final skor bekliyor, bakiyeler beklemiyor.</b><br>Baskın hesabın ekonomik rolü çözülemedi. Aşağıdaki miktar, yüzde, piyasa değeri ve sınırlı davranış kanıtları yine gerçektir.</div>':''}<div class="clean-list section-gap">${arr(h.findings).map((x,i)=>`<div class="summary-row"><span>#${i+1}</span><b style="text-align:left">${esc(x)}</b>${badge('verified')}</div>`).join('')}</div><div class="table-wrap section-gap"><table class="table"><thead><tr><th>#</th><th>Owner / kontrol yüzeyi</th><th>Token miktarı</th><th>Arz payı</th><th>Referans USD</th><th>Tutuş / aktivite</th><th>Davranış</th></tr></thead><tbody>${rows.slice(0,20).map(r=>`<tr><td><b>${num(r.rank)}</b></td><td><b class="mono">${esc(short(holderIdentity(r),28))}</b><div class="muted small">${esc(holderRoleLabel(r.role))} · ${num(r.token_account_count)} token account</div></td><td><b>${num(r.balance)}</b></td><td><b>${num(r.risk_bearing&&r.circulating_percentage?r.circulating_percentage:r.raw_percentage)}%</b><div class="muted small">${r.risk_bearing?'Dolaşım payı':'Ham arz · risk dışı'}</div></td><td><b>${r.reference_usd_value==null?'—':usd(r.reference_usd_value)}</b></td><td>${esc(holderDuration(r))}<div class="muted small">${r.newest_activity_observed_at?dt(r.newest_activity_observed_at):'Son hareket yok'}</div></td><td>${badge(r.behavior)}<div class="muted small">${esc(holderBehaviorLabel(r.behavior))}${r.outflow_transactions?` · ${num(r.outflow_transactions)} çıkış`:''}</div></td></tr>`).join('')}</tbody></table></div><div class="metadata section-gap"><div><label>Owner sayısı</label><b>${num(h.owner_count)}</b></div><div><label>Risk taşıyan owner</label><b>${num(h.risk_bearing_owner_count)}</b></div><div><label>Parsed wallet</label><b>${num(h.wallets_with_parsed_evidence)}</b></div><div><label>Çıkış gözlenen</label><b>${num(h.wallets_with_observed_outflow)}</b></div><div><label>Ortak çıkış grubu</label><b>${num(h.common_exit_group_count)}</b></div><div><label>Owner agregasyonu</label><b>${h.owner_aggregation_applied?'UYGULANDI':'YOK'}</b></div></div>${arr(h.limitations).length?`<details class="owner-details section-gap"><summary><span><b>Veri sınırları</b><small>Hangi değerlerin kesin, hangilerinin sınırlı gözlem olduğunu gösterir.</small></span><span>⌄</span></summary><div class="warning-box section-gap">${arr(h.limitations).map(esc).join(' · ')}</div></details>`:''}</details>`}
'''
text = replace_once(text, anchor, helpers + anchor, "holder intelligence helpers")

# Replace complete report body with holder-first UX.
pattern = re.compile(r'function radarReportHTML\(d\)\{.*?\}\n\nfunction wrapText', re.S)
replacement = r'''function radarReportHTML(d){const f=obj(d.final_verdict),dist=obj(d.holder_distribution),src=obj(d.source_context),struct=obj(d.structural_memory),mods=arr(d.modules),evidence=arr(d.evidence),cluster=obj(d.holder_cluster),holders=obj(d.holder_intelligence),market=obj(d.market||holders.market),accounts=arr(dist.top_accounts),scored=f.signed!==false&&Number.isFinite(Number(f.risk_index)),level=scored?(f.risk_level||'unknown'):'evidence_pending',scoreText=scored?`${num(f.risk_index)}/100`:'N/A';return`<div class="card" style="border-color:${riskClass(level)==='bad'?'#ff526f66':riskClass(level)==='warn'?'#ffc95c55':'#18ffb244'}"><div class="card-head"><div><span class="eyebrow">KOSCHEI ARVIS · HOLDER INTELLIGENCE</span><h2>${esc(String(level).toUpperCase())} · ${esc(scoreText)} · Grade ${esc(scored?(f.grade||'—'):'—')}</h2><div class="mono muted">${esc(d.target)}</div></div>${badge(level)}</div><p class="muted" style="font-size:15px;line-height:1.7">${esc(d.narrative||f.verdict||'Kanıt özeti üretilemedi.')}</p><div class="grid compact-grid">${kpi('Top owner',holders.available?num(holders.top_owner_percentage)+'%':dist.available?num(dist.top_1_percentage)+'%':'—','Owner bazında birleştirilmiş kontrol',holders.top_owner_percentage>=35?'tone-red':'tone-cyan','1')}${kpi('Top 10 owner',holders.available?num(holders.top_10_percentage)+'%':dist.available?num(dist.top_10_percentage)+'%':'—','Kümülatif owner yoğunluğu','tone-cyan','10')}${kpi('Token fiyatı',market.price_usd?usd(market.price_usd,10):'—','En likit Solana pair','tone-cyan','$')}${kpi('Piyasa değeri',market.market_cap_usd?usd(market.market_cap_usd):'—',`24s hacim ${market.volume_24h_usd?usd(market.volume_24h_usd):'—'}`,'tone-cyan','◇')}</div><div class="metadata"><div><label>Toplam arz</label><b>${dist.available?num(dist.supply):'Gözlemlenmedi'}</b></div><div><label>Creator / deployer</label><b class="mono">${esc(src.creator_wallet||'Kaynakta gözlemlenmedi')}</b></div><div><label>Mint authority</label><b>${struct.has_authority_data?(struct.mint_authority_present?'AÇIK':'KAPALI'):'Gözlemlenmedi'}</b></div><div><label>Freeze authority</label><b>${struct.has_authority_data?(struct.freeze_authority_present?'AÇIK':'KAPALI'):'Gözlemlenmedi'}</b></div><div><label>Likidite</label><b>${market.liquidity_usd?usd(market.liquidity_usd):'—'}</b></div><div><label>İmza</label><b class="mono">${esc(short(f.signature,45))}</b></div></div><div class="section-gap" style="display:flex;gap:8px;flex-wrap:wrap"><button class="btn primary" data-download-poster type="button">Holder Görselini İndir</button><button class="btn" data-copy-summary type="button">Açıklamayı Kopyala</button></div><canvas data-radar-poster width="1200" height="1900" style="width:min(100%,700px);display:block;margin:14px auto;border:1px solid #1de6c833;border-radius:18px;background:#02070d"></canvas>${holderIntelligenceHTML(holders)}${holderClusterHTML(cluster)}<details class="owner-details section-gap"><summary><span><b>Tüm ARVIS modülleri</b><small>Final hükmün hangi doğrulanmış kollardan üretildiğini gösterir.</small></span><span>⌄</span></summary><div class="table-wrap section-gap"><table class="table"><thead><tr><th>Modül</th><th>Risk</th><th>Durum</th><th>Karar</th></tr></thead><tbody>${mods.map(m=>`<tr><td><b>${esc(m.module||m.module_id)}</b><div class="mono">${esc(m.module_id)}</div></td><td>${m.signed?num(m.risk_index)+'/100':'N/A'}</td><td>${badge(m.risk_level||m.evidence_status)}</td><td>${esc(m.verdict||m.recommendation||'Kanıt yok')}</td></tr>`).join('')}</tbody></table></div></details><details class="owner-details section-gap"><summary><span><b>Kanıt günlüğü</b><small>${num(evidence.length)} insan-okunur kanıt satırı</small></span><span>⌄</span></summary><div class="clean-list section-gap">${evidence.map((x,i)=>`<div class="summary-row"><span>#${i+1}</span><b style="text-align:left">${esc(typeof x==='string'?x:(x.text||JSON.stringify(x)))}</b>${badge(x&&typeof x==='object'&&x.verified===true?'verified':'unavailable')}</div>`).join('')||'<div class="empty">Kanıt satırı yok.</div>'}</div></details><details class="owner-details section-gap"><summary><span><b>Teknik token-account rolleri</b><small>Owner agregasyonundan önceki ham Top-20 hesap yüzeyi.</small></span><span>⌄</span></summary>${accounts.length?`<div class="table-wrap section-gap"><table class="table"><thead><tr><th>#</th><th>Token account</th><th>Owner wallet / PDA</th><th>Rol</th><th>Bakiye</th><th>Ham pay</th><th>Dolaşım payı</th></tr></thead><tbody>${accounts.map(a=>`<tr><td>${a.rank}</td><td class="mono">${esc(short(a.token_account,30))}</td><td class="mono">${esc(short(a.owner_wallet,30))}</td><td>${badge(a.role||'unknown')}<div class="muted small">${esc(holderRoleLabel(a.role))}</div></td><td>${num(a.balance)}</td><td>${num(a.raw_percentage)}%</td><td>${a.excluded_from_holder_risk?'—':num(a.circulating_percentage)+'%'}</td></tr>`).join('')}</tbody></table></div>`:'<div class="empty section-gap">Holder hesabı verisi alınamadı.</div>'}</details></div>`}

function wrapText'''
text, count = pattern.subn(replacement, text, count=1)
if count != 1:
    raise SystemExit("radarReportHTML replacement failed")

# Replace poster with a real top-holder leaderboard and factual explanation.
poster_pattern = re.compile(r'function drawPoster\(canvas,d\)\{.*?\}\nfunction bindRadarResult', re.S)
poster_replacement = r'''function drawPoster(canvas,d){if(!canvas)return;canvas.width=1200;canvas.height=1900;const c=canvas.getContext('2d'),f=obj(d.final_verdict),h=obj(d.holder_intelligence),m=obj(d.market||h.market),rows=arr(h.rows),scored=f.signed!==false&&Number.isFinite(Number(f.risk_index)),level=scored?String(f.risk_level||'unknown').toUpperCase():'EVIDENCE PENDING',danger=['HIGH','CRITICAL'].includes(level),accent=danger?'#ff526f':level==='MEDIUM'?'#ffc95c':'#18ffb2',g=c.createLinearGradient(0,0,1200,1900);g.addColorStop(0,'#02070d');g.addColorStop(.55,'#071824');g.addColorStop(1,'#020409');c.fillStyle=g;c.fillRect(0,0,1200,1900);c.strokeStyle='#1de6c855';c.lineWidth=3;c.strokeRect(28,28,1144,1844);c.fillStyle='#18ffb2';c.font='900 28px Arial';c.fillText('KOSCHEI WEB3',70,88);c.fillStyle='#fff';c.font='900 62px Arial';c.fillText('HOLDER INTELLIGENCE',70,165);c.fillStyle=accent;c.font='900 38px Arial';c.fillText(scored?`${level} · ${Number(f.risk_index)}/100`:'EVIDENCE PENDING · FACTS VISIBLE',70,225);c.fillStyle='#9bb2c2';c.font='22px monospace';wrapText(c,d.target,70,275,1060,30,2);c.strokeStyle='#1de6c833';c.strokeRect(70,330,1060,190);c.fillStyle='#8effe2';c.font='800 21px Arial';c.fillText('MARKET SNAPSHOT',100,375);const marketRows=[['PRICE',m.price_usd?usd(m.price_usd,10):'—'],['MARKET CAP',m.market_cap_usd?usd(m.market_cap_usd):'—'],['24H VOLUME',m.volume_24h_usd?usd(m.volume_24h_usd):'—'],['LIQUIDITY',m.liquidity_usd?usd(m.liquidity_usd):'—']];marketRows.forEach((r,i)=>{const x=100+i*255;c.fillStyle='#8299aa';c.font='700 16px Arial';c.fillText(r[0],x,425);c.fillStyle='#fff';c.font='800 24px Arial';c.fillText(String(r[1]),x,475)});c.strokeStyle='#1de6c833';c.strokeRect(70,550,1060,180);c.fillStyle='#8effe2';c.font='800 21px Arial';c.fillText('OWNER-AGGREGATED CONCENTRATION',100,595);const conc=[['TOP 1',h.top_1_percentage],['TOP 3',h.top_3_percentage],['TOP 10',h.top_10_percentage],['TOP 20',h.top_20_percentage]];conc.forEach((r,i)=>{const x=100+i*255;c.fillStyle='#8299aa';c.font='700 16px Arial';c.fillText(r[0],x,645);c.fillStyle=accent;c.font='900 34px Arial';c.fillText(h.available?`${Number(r[1]||0).toFixed(2)}%`:'—',x,695)});c.strokeStyle='#1de6c333';c.strokeRect(70,760,1060,760);c.fillStyle='#8effe2';c.font='800 21px Arial';c.fillText('LARGEST CONTROL SURFACES',100,805);c.fillStyle='#708797';c.font='700 15px Arial';c.fillText('OWNER / ROLE',130,850);c.fillText('TOKEN',555,850);c.fillText('SHARE',760,850);c.fillText('USD VALUE',900,850);rows.slice(0,8).forEach((r,i)=>{const y=905+i*76;c.strokeStyle='#1de6c322';c.beginPath();c.moveTo(100,y+31);c.lineTo(1100,y+31);c.stroke();c.fillStyle='#18ffb2';c.font='800 19px Arial';c.fillText(`#${r.rank}`,100,y);c.fillStyle='#fff';c.font='800 19px monospace';c.fillText(short(holderIdentity(r),25),145,y);c.fillStyle='#718999';c.font='15px Arial';c.fillText(holderRoleLabel(r.role),145,y+23);c.fillStyle='#fff';c.font='800 18px Arial';c.fillText(num(r.balance),555,y);c.fillStyle=Number(r.risk_bearing&&r.circulating_percentage?r.circulating_percentage:r.raw_percentage)>=20?'#ff526f':'#8effe2';c.fillText(`${Number(r.risk_bearing&&r.circulating_percentage?r.circulating_percentage:r.raw_percentage||0).toFixed(2)}%`,760,y);c.fillStyle='#fff';c.fillText(r.reference_usd_value==null?'—':usd(r.reference_usd_value),900,y);c.fillStyle='#718999';c.font='14px Arial';c.fillText(`${holderDuration(r)} · ${holderBehaviorLabel(r.behavior)}`,555,y+23)});c.strokeStyle='#1de6c333';c.strokeRect(70,1550,1060,230);c.fillStyle='#8effe2';c.font='800 21px Arial';c.fillText('KOSCHEI EXPLANATION',100,1595);c.fillStyle='#fff';c.font='24px Arial';wrapText(c,d.narrative||f.verdict,100,1645,990,34,4);c.fillStyle='#18ffb2';c.font='800 18px monospace';c.fillText('EVIDENCE FIRST · AMOUNTS, OWNERS, VALUE, BEHAVIOR',70,1830);c.fillStyle='#6f8797';c.font='15px monospace';c.fillText(new Date(d.generated_at||Date.now()).toISOString(),70,1860)}
function bindRadarResult'''
text, count = poster_pattern.subn(poster_replacement, text, count=1)
if count != 1:
    raise SystemExit("drawPoster replacement failed")
text = replace_once(text, "a.download=`koschei-arvis-${String(d.target||'report').slice(0,10)}.png`", "a.download=`koschei-holder-intelligence-${String(d.target||'report').slice(0,10)}.png`", "poster filename")
path.write_text(text)

# Force the browser to fetch the holder-intelligence UI.
path = Path("public/owner-production.html")
text = path.read_text()
text = replace_once(text, '/js/owner-control-center.js?v=8', '/js/owner-control-center.js?v=9', "owner cache v9")
path.write_text(text)
